def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        bin_capacity = bins[i]
        if bin_capacity <= 0:
            priorities[i] = np.inf
            continue
        if item > bin_capacity:
            priorities[i] = np.inf
            continue
        ratio = item / bin_capacity
        score = 0
        if ratio < 0.2:
            score = bin_capacity * 0.5
            for j in range(1, 4):
                score += (ratio ** j) * 10
        elif 0.2 <= ratio <= 0.8:
            score = -np.log(ratio) * (bin_capacity ** 0.5)
            for k in range(1, 3):
                score += ((1 - ratio) ** k) * 5
        else:
            score = (1 - ratio) * 100
            if bin_capacity > 50:
                score /= 2
            else:
                score *= 2
        priorities[i] = score
    return priorities
